using UnityEngine;
public class Script
{
    public static object Main()
    {
        // 找最近的动物
        var animals = Object.FindObjectsOfType<FL.Gameplay.Modules.BigWorld.AnimalController>();
        if (animals.Length == 0) return "No animals found";

        // 找玩家
        var playerMgr = FL.Gameplay.Manager.PlayerManager.Instance;
        if (playerMgr == null) return "PlayerManager null";
        var localPlayer = playerMgr.LocalPlayer;
        if (localPlayer == null) return "LocalPlayer null";

        Vector3 playerPos = localPlayer.transform.position;

        // 找最近的动物
        FL.Gameplay.Modules.BigWorld.AnimalController nearest = null;
        float minDist = float.MaxValue;
        foreach (var a in animals)
        {
            float d = Vector3.Distance(a.transform.position, playerPos);
            if (d < minDist) { minDist = d; nearest = a; }
        }

        return "NearestAnimal NetId=" + nearest.NetId + " dist=" + minDist.ToString("F1") + " pos=" + nearest.transform.position;
    }
}
